# Shape implementations module

from types import Color, Point, Shape, Renderable, Measurable

class Circle(Shape):
    radius: float

    def __init__(self, color: Color, position: Point, radius: float):
        super().__init__(color, position)
        self.radius = radius

    @override
    def get_name(self) -> str:
        return "circle"

    @override
    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def perimeter(self) -> float:
        return 2.0 * 3.14159 * self.radius

    @override
    def render(self) -> str:
        return f"Circle(r={self.radius}, color={self.color})"

    @override
    def describe(self) -> str:
        base: str = super().describe()
        return f"{base} with radius {self.radius}"

class Rectangle(Shape):
    width: float
    height: float

    def __init__(self, color: Color, position: Point, width: float, height: float):
        super().__init__(color, position)
        self.width = width
        self.height = height

    @override
    def get_name(self) -> str:
        return "rectangle"

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    @override
    def render(self) -> str:
        return f"Rectangle({self.width}x{self.height}, color={self.color})"

class Triangle(Shape):
    p1: Point
    p2: Point
    p3: Point

    def __init__(self, color: Color, position: Point, p1: Point, p2: Point, p3: Point):
        super().__init__(color, position)
        self.p1 = p1
        self.p2 = p2
        self.p3 = p3

    @override
    def get_name(self) -> str:
        return "triangle"

    @override
    def area(self) -> float:
        # Using shoelace formula
        a: float = self.p1.x * (self.p2.y - self.p3.y)
        b: float = self.p2.x * (self.p3.y - self.p1.y)
        c: float = self.p3.x * (self.p1.y - self.p2.y)
        return abs((a + b + c) / 2.0)

    @override
    def perimeter(self) -> float:
        return self.p1.distance_to(self.p2) + self.p2.distance_to(self.p3) + self.p3.distance_to(self.p1)

    @override
    def render(self) -> str:
        return f"Triangle({self.p1}, {self.p2}, {self.p3})"

