# Utility functions for shape operations

from types import Color, Point
from shapes import Circle, Rectangle, Triangle

def create_origin_point() -> Point:
    return Point(0.0, 0.0)

def create_unit_circle(color: Color) -> Circle:
    return Circle(color, create_origin_point(), 1.0)

def create_square(color: Color, size: float) -> Rectangle:
    return Rectangle(color, create_origin_point(), size, size)

def calculate_total_area(shapes: list[Circle]) -> float:
    total: float = 0.0
    for shape in shapes:
        total += shape.area()
    return total

def color_from_string(name: str) -> Color:
    if name == "red":
        return Color.RED
    elif name == "green":
        return Color.GREEN
    elif name == "blue":
        return Color.BLUE
    else:
        return Color.BLACK
